pe=\"text\" name=\"title\" v-model=\"title\" class=\"tw-form-control w-full\" placeholder=\"Enter Title\" @keyup='remaincharCount(25)' :maxlength=\"25\">\n                                    <div class=\"text-gray-700 text-xs my-1\" v-text=\"(25 - title.length)+'/'+25\" style=\"text-align: right\"></div>               \n                                    <span v-if=\"errors.title\" class=\"text-red-500 text-xs font-semibold\">{{errors.title[0]}}</span>\n                                </div>\n                            </div>\n                        </div>\n                        <div class=\"my-6\">\n                            <a href=\"#\" class=\"btn btn-submit blue-bg text-white rounded px-3 py-1 mr-3 text-sm font-medium\" @click=\"submit(holiday['id'])\">Submit</a>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n</template>\n\n<script>\n    import datetime from 'vuejs-datetimepicker';\n    export default {\n        props:['url','mode'],\n        components: { datetime},\n        data () {\n            return {\n                holidays:[],\n                date:'',\n                title:'',\n                show:'',\n                errors:[],\n                success:null, \n                total: 0,\n                page: 1,\n                page_count: 0,\n            }\n        },\n\n        methods:\n        {\n            getData(page=1)\n            {\n                axios.get('/'+this.mode+'/holidays/list?page='+page).then(response => {\n                    this.holidays = response.data.data;\n                    this.page_count = response.data.meta.last_page;\n                    this.total = response.data.meta.total;\n                    //console.log(this.holidays);   \n                });\n            },\n\n            showEdit(id)\n            {\n                this.show = id;\n                axios.get('/'+this.mode+'/holiday/edit/'+id).then(response => {\n                    this.date = response.data.date;\n                    this.title = response.data.title;\n                    //console.log(this.holidays);   \n                });\n            },\n\n            closeModal()\n            {\n                this.show = 0;\n            },\n\n            remaincharCount(len)\n            {\n                var maxLength = len;\n                $('textarea').keyup(function() {\n                    var textlen = maxLength - $(this).val().length+'/'+maxLength;\n                    $('#rchars').text(textlen);\n                });\n            },\n\n            submit(id)\n            {\n                this.errors=[];\n                this.success=null;\n\n                let formData=new FormData(); \n\n                formData.append('date',this.date);\n                formData.append('title',this.title);\n\n                axios.post('/'+this.mode+'/holiday/edit/'+id,formData,{headers: {'Content-Type': 'multipart/form-data'}}).then(response => {     \n                    this.success = response.data.success;\n                    this.closeModal(); \n                    window.location.reload();\n                }).catch(error => {\n                    this.errors = error.response.data.errors;\n                });\n            },\n\n            deleteHoliday(id) \n            {\n                var thisswal = this;\n                swal({\n                    title: 'Are you sure',\n                    text: 'Do you want to delete this Holiday ?',\n                    icon: \"info\",\n                    buttons: [\n                        'No',\n                        'Yes'\n                    ],\n                    dangerMode: true,\n                }).then(function(isConfirm) {\n                    if (isConfirm) \n                    {\n                        axios.get(thisswal.url+ '/'+thisswal.mode+'/holiday/delete/'+ id).then(response => {\n                            thisswal.success = response.data.success;\n                            window.location.reload();\n                        }); \n                    }\n                    else \n                    {\n                        swal(\"Cancelled\");\n                    }\n                });\n            },\n        },\n  \n        created()\n        {   \n            this.getData(); \n        }\n    }\n</script>\n\n<style scoped>\n    .modal-mask {\n        position: fixed;\n        z-index: 9998;\n        top: 0;\n        left: 0;\n        width: 100%;\n        height: 100%;\n        background-color: rgba(0, 0, 0, .5);\n        display: table;\n        transition: opacity .3s ease;\n    }\n\n    .modal-wrapper {\n        display: table-cell;\n        vertical-align: middle;\n        overflow:auto;\n    }\n\n    .modal-container-new {\n        margin: 0px auto;\n        /*padding: 20px 30px;*/\n        background-color: #fff;\n        border-radius: 2px;\n        box-shadow: 0 2px 8px rgba(0, 0, 0, .33);\n        transition: all .3s ease;\n        height: 500px;\n        overflow:auto;\n    }\n\n    .modal-container {\n        margin: 0px auto;\n        /*padding: 20px 30px;*/\n        background-color: #fff;\n        border-radius: 2px;\n        box-shadow: 0 2px 8px rgba(0, 0, 0, .33);\n        transition: all .3s ease;\n        /*height: 500px;*/\n        overflow:auto;\n    }\n\n    .modal-header h3 {\n        margin-top: 0;\n        color: #42b983;\n    }\n\n    .modal-body {\n        margin: 20px 0;\n    }\n\n    .modal-default-button {\n        float: right;\n    }\n\n    /*\n     * The following styles are auto-applied to elements with\n     * transition=\"modal\" when their visibility is toggled\n     * by Vue.js.\n     *\n     * You can easily play with the modal transition by editing\n     * these styles.\n     */\n    .modal-enter {\n        opacity: 0;\n    }\n\n    .modal-leave-active {\n        opacity: 0;\n    }\n\n    .modal-enter .modal-container,\n    .modal-leave-active .modal-container {\n        -webkit-transform: scale(1.1);\n        transform: scale(1.1);\n    }\n</style>"],"sourceRoot":""}]);
